function [logTitle,logData,nmbClmn,nmbSht,bgData] = fLogReadV07(fName)%% reads logfile and return title and data% % [logTitle,logData,nmbClmn,nmbSht,bgData] = fLogReadV07(fName)% % logTitle: cell of the column number and log title% logData: cell of the data (string, not numeric)% nmbClmn: number of column in the log% nmbSht: number of shots in the log% bgData: back ground data%% fName: file path%%% Function Log Reader, ver.7% % Kei Nakamura% 2013/1/3 ver.4: for new control system% 2013/1/17 ver.5: make compatible with matlab log% 2013/1/25 ver.6: Old system log problem, new system background data% 2013/1/29 ver.7: excel made text file had different CR.% 2014/4/14 ver.7.1: fix for background shot >2% 2018/7/24 ver.7.2: new excel changed end of the line character%% load file into a big stringaa = fileread(fName);   % log file in a long string%% find out log-kindbb = find(aa==10);  % finding "end of the line character"if isempty(bb)    excL = 1;   % if no "10", excel made log    bb = find(aa==13);  % need to find "13"    bb = [bb,numel(aa)+1];  % there is no "13" at the last line for excel    lvL = 0;    oldL = 0;else    % lab view logic, 1 for lavbiew log, 0 for matlab log    lvL = ~isempty(find(aa==13, 1));      oldL = double(aa(bb(1)-1-lvL))==9; % old log logic (tab at the end)    if double(aa(end))~=10  % this is new excel log        bb = [bb,numel(aa)+1]; %         lvL = 0;    endend%% find out how many columns and rowstitleLine = aa(1:bb(1)-1-lvL-oldL);    % extract title linetitleLLength = numel(titleLine);      % title line lengthtitleLTab = find(titleLine==9);       % title line tab, find tab in title linetitleLTab = [0,titleLTab,titleLLength+1]; % add tabs artificailly at the beginning and end for later conveniencenmbClmn = numel(titleLTab) - 1;   % number of column would be -1.nmbSht = numel(bb)-1;   % number of shots is the rows -1 (title row)%% make cell array of column number and titlelogTitle = cell(nmbClmn,2);   % title column, allocate empty cell arraystart1 = 1; % for the beginningfor ii = 1:nmbClmn % for the number of column    logTitle{ii,1} = ii;   % column number    logTitle{ii,2} = titleLine(start1:titleLTab(ii+1)-1);    start1 = titleLTab(ii+1)+1;    % for the beginning of the next lineend%% put data in cell arraylogData = cell(nmbSht,nmbClmn); % log data, allocationdataLTab = zeros(1,nmbClmn+1);  % allocationfor ii = 1:nmbSht   % go shot by shot for now    dataLine = aa(bb(ii)+1:bb(ii+1)-1-lvL-oldL); % extract each line (shot)    dataLLength = numel(dataLine);      % data line length    dataLTab(2:end-1) = find(dataLine==9); % find tabs for each line    dataLTab(end) = dataLLength+1;  % add tab artificailly at the end    dataElmLength = diff(dataLTab)-1;  % to find data element length    % place data on each column element    strtL = 1;    for jj = 1:nmbClmn        if dataElmLength(jj)>0 % dataElmLength=0 is empty cell            logData{ii,jj} = dataLine(strtL:dataLTab(jj+1)-1);    % put data in cell        end        strtL = dataLTab(jj+1)+1;    endend%% new log has background shot infobgData = cell(1,1); % in case of no background data[sCheck,~] = size(logData); % shot checkif sCheck==0    nmbSht = 0;    disp ('empty log')    returnendif lvL==1&&oldL==0 % meaning new log file     clmNmb = fLogClmnFindV01(logTitle,'Shotnumber','');    % find out where the shot numebr is    if clmNmb~=0    % if shotnumbers isn't there, random log from labview        shot1 = str2double(logData(1,clmNmb));  % what's the first shot number?        if shot1<=-1    % if the first shot number = -1, back ground            nmbBG = abs(shot1); % number of bg            logData = logData(1+nmbBG:end,:);            bgData = logData(1:nmbBG,:);            nmbSht = nmbSht - nmbBG;    % shot number -1.        end    endend%% old log sometime has extra shot at the endif lvL==1&&oldL==1 % meaning old log file    clmNmb = fLogClmnFindV01(logTitle,'shotnumbers','');    % find out where the shot numebr is    if clmNmb~=0    % if shotnumbers isn't there, random log from labview        shotE = str2double(logData(end,clmNmb));  % what's the end shot number?        if shotE==0    % if the end shot number = 0, remove it            logData = logData(1:end-1,:);            nmbSht = nmbSht - 1;    % shot number -1.        end    endendend
